 57→
 58→  const stableProps = useStable({
 59→    app,
 60→    onCancel,
 61→    onChange,
 62→    onSelect,
 63→    selectedElements,
 64→  });
 65→
 66→  const { container: excalidrawContainer } = useExcalidrawContainer();
 67→
 68→  useEffect(() => {
 69→    const colorPreviewDiv = ref.current;
 70→
 71→    if (!colorPreviewDiv || !app.canvas || !eyeDropperContainer) {
 72→      return;
 73→    }
 74→
 75→    let isHoldingPointerDown = false;
 76→
 77→    const ctx = app.canvas.getContext("2d")!;
 78→
 79→    const getCurrentColor = ({
 80→      clientX,
 81→      clientY,
 82→    }: {
 83→      clientX: number;
 84→      clientY: number;
 85→    }) => {
 86→      const pixel = ctx.getImageData(
 87→        (clientX - appState.offsetLeft) * window.devicePixelRatio,
 88→        (clientY - appState.offsetTop) * window.devicePixelRatio,
 89→        1,
 90→        1,
 91→      ).data;
 92→
 93→      return rgbToHex(pixel[0], pixel[1], pixel[2]);
 94→    };
 95→
 96→    const mouseMoveListener = ({
 97→      clientX,
 98→      clientY,
 99→      altKey,
100→    }: {
101→      clientX: number;
102→      clientY: number;
103→      altKey: boolean;
104→    }) => {
105→      // FIXME swap offset when the preview gets outside viewport
106→      colorPreviewDiv.style.top = `${clientY + 20}px`;
107→      colorPreviewDiv.style.left = `${clientX + 20}px`;
