167→
168→    // init color preview else it would show only after the first mouse move
169→    mouseMoveListener({
170→      clientX: stableProps.app.lastViewportPosition.x,
171→      clientY: stableProps.app.lastViewportPosition.y,
172→      altKey: false,
173→    });
174→
175→    eyeDropperContainer.addEventListener(EVENT.KEYDOWN, keyDownListener);
176→    eyeDropperContainer.addEventListener(
177→      EVENT.POINTER_DOWN,
178→      pointerDownListener,
179→    );
180→    eyeDropperContainer.addEventListener(EVENT.POINTER_UP, pointerUpListener);
181→    window.addEventListener("pointermove", mouseMoveListener, {
182→      passive: true,
183→    });
184→    window.addEventListener(EVENT.BLUR, onCancel);
185→
186→    return () => {
187→      isHoldingPointerDown = false;
188→      eyeDropperContainer.removeEventListener(EVENT.KEYDOWN, keyDownListener);
189→      eyeDropperContainer.removeEventListener(
190→        EVENT.POINTER_DOWN,
191→        pointerDownListener,
192→      );
193→      eyeDropperContainer.removeEventListener(
194→        EVENT.POINTER_UP,
195→        pointerUpListener,
196→      );
197→      window.removeEventListener("pointermove", mouseMoveListener);
198→      window.removeEventListener(EVENT.BLUR, onCancel);
199→    };
200→  }, [
201→    stableProps,
202→    app.canvas,
203→    eyeDropperContainer,
204→    colorPickerType,
205→    excalidrawContainer,
206→    appState.offsetLeft,
207→    appState.offsetTop,
208→  ]);
209→
210→  const ref = useRef<HTMLDivElement>(null);
211→
212→  useOutsideClick(
213→    ref,
214→    () => {
215→      onCancel();
216→    },
217→    (event) => {
218→      if (
219→        event.target.closest(
220→          ".excalidraw-eye-dropper-trigger, .excalidraw-eye-dropper-backdrop",
221→        )
222→      ) {
223→        return true;
224→      }
225→      // consider all other clicks as outside
