227→    },
228→  );
229→
230→  if (!eyeDropperContainer) {
231→    return null;
232→  }
233→
234→  return createPortal(
235→    <div ref={ref} className="excalidraw-eye-dropper-preview" />,
236→    eyeDropperContainer,
