/** Offset in px between the pointer and the near edge of the preview square. */
export const PREVIEW_OFFSET = 20;
/** The preview is a 3 rem (48 px) square. */
export const PREVIEW_SIZE = 48;
/** Minimum gap between the preview and the viewport edge. */
export const PREVIEW_MARGIN = 10;

