export const getPreviewPosition = (
  clientX: number,
  clientY: number,
  viewportWidth: number,
  viewportHeight: number,
): { left: number; top: number } => {
  let left = clientX + PREVIEW_OFFSET;
  if (left + PREVIEW_SIZE + PREVIEW_MARGIN > viewportWidth) {
    left = clientX - PREVIEW_OFFSET - PREVIEW_SIZE;
