import {
  getPreviewPosition,
  PREVIEW_OFFSET,
  PREVIEW_SIZE,
  PREVIEW_MARGIN,
} from "./EyeDropper";

// Viewport used for most tests: 1920 × 1080
const W = 1920;
const H = 1080;

describe("getPreviewPosition", () => {
  // ------------------------------------------------------------------
  // Default placement (bottom-right of pointer)
  // ------------------------------------------------------------------
  it("places the preview to the bottom-right of the pointer by default", () => {
    const { left, top } = getPreviewPosition(400, 300, W, H);
    expect(left).toBe(400 + PREVIEW_OFFSET);
    expect(top).toBe(300 + PREVIEW_OFFSET);
  });

  // ------------------------------------------------------------------
  // Right edge  → flip horizontally
  // ------------------------------------------------------------------
  it("flips to the left of the pointer near the right viewport edge", () => {
    const clientX = W - 30; // 30 px from right edge — not enough room
    const { left } = getPreviewPosition(clientX, 300, W, H);

    expect(left).toBe(clientX - PREVIEW_OFFSET - PREVIEW_SIZE);
    // Must stay inside the viewport
    expect(left).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
    expect(left + PREVIEW_SIZE).toBeLessThanOrEqual(W - PREVIEW_MARGIN);
  });

  // ------------------------------------------------------------------
  // Bottom edge → flip vertically
  // ------------------------------------------------------------------
  it("flips above the pointer near the bottom viewport edge", () => {
    const clientY = H - 30;
    const { top } = getPreviewPosition(400, clientY, W, H);

    expect(top).toBe(clientY - PREVIEW_OFFSET - PREVIEW_SIZE);
    expect(top).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
    expect(top + PREVIEW_SIZE).toBeLessThanOrEqual(H - PREVIEW_MARGIN);
  });

  // ------------------------------------------------------------------
  // Bottom-right corner → flip both axes
  // ------------------------------------------------------------------
  it("flips both axes when pointer is in the bottom-right corner", () => {
    const clientX = W - 30;
    const clientY = H - 30;
    const { left, top } = getPreviewPosition(clientX, clientY, W, H);

    expect(left).toBe(clientX - PREVIEW_OFFSET - PREVIEW_SIZE);
    expect(top).toBe(clientY - PREVIEW_OFFSET - PREVIEW_SIZE);
    expect(left).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
    expect(top).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
  });

  // ------------------------------------------------------------------
  // Left edge — already on the preferred side, no flip needed
  // ------------------------------------------------------------------
  it("keeps the default right placement when near the left edge", () => {
    const { left } = getPreviewPosition(5, 300, W, H);
    expect(left).toBe(5 + PREVIEW_OFFSET);
  });

  // ------------------------------------------------------------------
  // Top edge — already on the preferred side, no flip needed
  // ------------------------------------------------------------------
  it("keeps the default bottom placement when near the top edge", () => {
    const { top } = getPreviewPosition(400, 5, W, H);
    expect(top).toBe(5 + PREVIEW_OFFSET);
  });

  // ------------------------------------------------------------------
  // Top-left corner — no flip, default placement works
  // ------------------------------------------------------------------
  it("uses default placement in the top-left corner", () => {
    const { left, top } = getPreviewPosition(0, 0, W, H);
    expect(left).toBe(PREVIEW_OFFSET);
    expect(top).toBe(PREVIEW_OFFSET);
  });

  // ------------------------------------------------------------------
  // Tiny viewport — clamp even after flipping
  // ------------------------------------------------------------------
  it("clamps to PREVIEW_MARGIN in a viewport too small for the preview", () => {
    const tinyW = PREVIEW_SIZE + PREVIEW_MARGIN * 2; // bare minimum
    const tinyH = PREVIEW_SIZE + PREVIEW_MARGIN * 2;

    const { left, top } = getPreviewPosition(
      tinyW - 5, // near right edge → tries to flip, still clamped
      tinyH - 5,
      tinyW,
      tinyH,
    );

    expect(left).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
    expect(left + PREVIEW_SIZE).toBeLessThanOrEqual(tinyW - PREVIEW_MARGIN);
    expect(top).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
    expect(top + PREVIEW_SIZE).toBeLessThanOrEqual(tinyH - PREVIEW_MARGIN);
  });

  // ------------------------------------------------------------------
  // Exact boundary — preview just fits without flipping
  // ------------------------------------------------------------------
  it("does not flip when the preview exactly fits at the boundary", () => {
    // Place pointer so that preview's far edge lands exactly at the margin
    const clientX = W - PREVIEW_OFFSET - PREVIEW_SIZE - PREVIEW_MARGIN;
    const clientY = H - PREVIEW_OFFSET - PREVIEW_SIZE - PREVIEW_MARGIN;

    const { left, top } = getPreviewPosition(clientX, clientY, W, H);
    expect(left).toBe(clientX + PREVIEW_OFFSET);
    expect(top).toBe(clientY + PREVIEW_OFFSET);
  });

  // ------------------------------------------------------------------
  // One pixel past the boundary — flip triggers
  // ------------------------------------------------------------------
  it("flips when the preview would exceed the boundary by one pixel", () => {
    const clientX = W - PREVIEW_OFFSET - PREVIEW_SIZE - PREVIEW_MARGIN + 1;
    const clientY = H - PREVIEW_OFFSET - PREVIEW_SIZE - PREVIEW_MARGIN + 1;

    const { left, top } = getPreviewPosition(clientX, clientY, W, H);
    expect(left).toBe(clientX - PREVIEW_OFFSET - PREVIEW_SIZE);
    expect(top).toBe(clientY - PREVIEW_OFFSET - PREVIEW_SIZE);
  });

  // ------------------------------------------------------------------
  // Regression: old code would produce off-screen values
  // ------------------------------------------------------------------
  it("never returns a position that puts the preview outside the viewport", () => {
    // Sweep a selection of edge positions
    const positions = [
      [0, 0],
      [W, 0],
      [0, H],
      [W, H],
      [W / 2, H],
      [W, H / 2],
      [W - 1, H - 1],
      [1, 1],
    ];

    for (const [cx, cy] of positions) {
      const { left, top } = getPreviewPosition(cx, cy, W, H);
      expect(left).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
      expect(top).toBeGreaterThanOrEqual(PREVIEW_MARGIN);
      expect(left + PREVIEW_SIZE).toBeLessThanOrEqual(W - PREVIEW_MARGIN);
      expect(top + PREVIEW_SIZE).toBeLessThanOrEqual(H - PREVIEW_MARGIN);
    }
  });
});

