export const PREVIEW_MARGIN = 10;

/**
 * Return the `top` and `left` CSS values that keep the eyedropper preview
 * fully inside the viewport.  The preview is placed to the bottom-right of
 * the pointer by default and flips to the opposite side on each axis when it
 * would overflow.
 */
export const getPreviewPosition = (
  clientX: number,
  clientY: number,
  viewportWidth: number,
  viewportHeight: number,
): { left: number; top: number } => {
  let left = clientX + PREVIEW_OFFSET;
  if (left + PREVIEW_SIZE + PREVIEW_MARGIN > viewportWidth) {
    left = clientX - PREVIEW_OFFSET - PREVIEW_SIZE;
  }
  // still clamp in case even the flipped side overflows (tiny viewport)
  left = Math.max(PREVIEW_MARGIN, Math.min(left, viewportWidth - PREVIEW_SIZE - PREVIEW_MARGIN));

  let top = clientY + PREVIEW_OFFSET;
  if (top + PREVIEW_SIZE + PREVIEW_MARGIN > viewportHeight) {
    top = clientY - PREVIEW_OFFSET - PREVIEW_SIZE;
  }
  top = Math.max(PREVIEW_MARGIN, Math.min(top, viewportHeight - PREVIEW_SIZE - PREVIEW_MARGIN));

  return { left, top };
};

export type EyeDropperProperties = {
  keepOpenOnAlt: boolean;
  swapPreviewOnAlt?: boolean;
  /** called when user picks color (on pointerup) */
  onSelect: (color: string, event: PointerEvent) => void;
  /**
   * property of selected elements to update live when alt-dragging.
   * Supply `null` if not applicable (e.g. updating the canvas bg instead of
   * elements)
   **/
  colorPickerType: ColorPickerType;
};

export const activeEyeDropperAtom = atom<null | EyeDropperProperties>(null);

